$_MODULE['<{retractationcommande}prestashop>modal_f64e4c1e50abe85bbda9fd9abadcaa91'] = 'By confirming, your withdrawal request is sent to our customer service and an acknowledgment of receipt is sent to you by email with a PDF copy (art. L221-21 of the French Consumer Code). After verification of eligibility (legal period, exclusions under art. L221-28), the return procedure will be communicated to you — please do not return the products before receiving it. The refund is made no later than 14 days after recovery of the goods or receipt of proof of shipment (delivery costs included in the event of full withdrawal, pro rata otherwise). Return costs remain at your expense.';
$_MODULE['<{retractationcommande}prestashop>modal_a50e61a0c90d69685028d751c58e4b92'] = 'By confirming, your withdrawal request is sent to our customer service and an acknowledgment of receipt is sent to you by email with a PDF copy (art. L221-21 of the French Consumer Code). As your order has not yet been shipped, no product return will be necessary: after verification (exclusions under art. L221-28), the shipment will be cancelled and the full amount paid will be refunded to you no later than 14 days after your request, using the same means of payment.';
$_MODULE['<{retractationcommande}prestashop>formulaire_c690c88abeab5fe0fa53c961a8c22564'] = 'Exercise my right of withdrawal';
