$_MODULE['<{retractationcommande}prestashop>formulaire_e1b2374a2b9670a77ca0c7ae9199ad3a'] = 'This order is not (or no longer) eligible for online withdrawal: legal period expired, request already submitted or order not concerned. For any question, please contact our customer service.';
$_MODULE['<{retractationcommande}prestashop>formulaire_8fdb7ef7cb418c21ac083c86b78ce700'] = 'The right of withdrawal does not apply to certain contracts (art. L221-28 of the Consumer Code: made-to-measure or personalised goods, perishable goods, goods unsealed for hygiene reasons, etc.). After submission, your request is verified by our customer service, which sends you the return procedure. The refund is made no later than 14 days after recovery of the goods or receipt of proof of shipment, using the same means of payment. Return costs remain at your expense.';
