$_MODULE['<{retractationcommande}prestashop>pdf-accuse_d7946d02e12c5949ea9345ba89b095c4'] = 'Partial withdrawal: delivery costs are refunded pro rata to the goods returned (art. L221-24 of the French Consumer Code). The final amount will be confirmed to you by our customer service.';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_a326ee07399805b54dda859c82d08e17'] = 'Consumer\'s message';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b6aaa57d1a0559fa210245cf8167735e'] = 'Next steps';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_fb258aad76f4abfa89becfda83844199'] = 'Your request will be verified by our customer service (compliance with the legal period, exclusions provided for in article L221-28 of the French Consumer Code). If it is compliant, the return procedure will be sent to you by email. Please do not return the product(s) before receiving it. The refund will be made no later than 14 days after recovery of the goods or receipt of proof of shipment, using the same means of payment as used for the order (art. L221-24). Direct return costs remain at your expense (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_cfdcc6b063cf374f1884714702a0756f'] = 'As your order had not yet been shipped at the time of your request, no product return will be necessary. After verification by our customer service (exclusions provided for in article L221-28 of the French Consumer Code), the shipment will be cancelled and the full amount paid will be refunded to you no later than 14 days after your request, using the same means of payment as used for the order (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_5c2d9de00ffacf2c364b00b78de3b779'] = 'This document constitutes the acknowledgment of receipt of your withdrawal. Keep it — your reference to quote in any correspondence:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cd869423e6e1712e244df7d46926ae55'] = 'Reminder of your rights — right of withdrawal';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_28f6dc3c50525ce42dc3c3c6230b2e04'] = 'The period';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_24e62b7e04a04435c6493925063099d7'] = 'You have a period of 14 days to withdraw, without having to give a reason for your decision (art. L221-18 of the French Consumer Code). The count begins the day after delivery of the goods (or the conclusion of the contract for a service). If the period expires on a Saturday, Sunday or public holiday, it is extended until the next working day.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_ca4bdfe353ca54b512aa784846d90e0f'] = 'The refund';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_6541cabbb055c914336220caeaf4b99e'] = 'The refund covers the full amount paid, including standard delivery costs (pro rata in the event of partial withdrawal). It is made no later than 14 days after recovery of the goods or receipt of proof of their shipment, using the same means of payment as used for the order (art. L221-24). The direct costs of returning the goods remain at your expense (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_364ec46bb0eefd5863d785498e0c8539'] = 'The exceptions (art. L221-28)';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cb0665e6df823aae3b2992c440175070'] = 'The right of withdrawal cannot be exercised in particular for:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_7e1ea9778afc631312c1791d817f91c0'] = 'goods made to your specifications or clearly personalised;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0b6b365148cc6a798a4d9bec4e636d96'] = 'goods liable to deteriorate or expire rapidly;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_9efb6136f62e038628c899b282f64011'] = 'goods unsealed after delivery which cannot be returned for reasons of hygiene or health protection;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_8b8f626ccf32831a3fee474f675ea152'] = 'audio/video recordings or software unsealed after delivery;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_01449e6b663bbee9d407376945b3c9b6'] = 'digital content supplied without a tangible medium whose performance has begun with your consent;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_1d3b84dba66d1eb114fd8af178aa04d6'] = 'goods inseparably mixed with other items after delivery.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0095888b608335ea5982af9ada860f76'] = 'What happens next with your request';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_109c56e11ccf08ecc9e243bd1c4cb25f'] = 'Our customer service verifies your request and then sends you the return procedure by email. Please do not return the product(s) before receiving it, and return the goods complete, in their original condition.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_de7d1a2208e88e0679183aa747db6042'] = 'Order not shipped: no product return will be necessary. Our customer service verifies your request, cancels the shipment and proceeds with the refund.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_2f45a1c26bcfdf568c08ed1a390d3cbd'] = 'In the event of a dispute';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_804c0cd637a7c9607f4e30b77e11a8ba'] = 'If you consider that your request has not been handled in accordance with the regulations, you can contact our customer service and then refer the matter free of charge to a consumer mediator (art. L612-1 of the French Consumer Code).';
$_MODULE['<{retractationcommande}prestashop>order-detail_40333b8af27e3198afa43c960e43a3b8'] = 'Right of withdrawal';
$_MODULE['<{retractationcommande}prestashop>order-detail_c611966bbf00695038db11996b48d73a'] = 'Request';
