$_MODULE['<{retractationcommande}prestashop>demande_3a6a3681876ab1e4c55fdecb70fab698'] = 'The message contains characters that are not allowed.';
$_MODULE['<{retractationcommande}prestashop>demande_0f9a15225078e2688ee78b984640f46d'] = 'Requested quantity exceeds the quantity available for withdrawal.';
$_MODULE['<{retractationcommande}prestashop>demande_36c075970e7709b21dc06b19cb75c19e'] = 'Select at least one product to withdraw.';
$_MODULE['<{retractationcommande}prestashop>demande_b0998d501f75050aa4045d17399c25d0'] = 'Unable to save the request. Please contact customer service.';
$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Your withdrawal has been registered under reference %s. An acknowledgment of receipt has been sent to you by email. Our customer service will verify your request and send you the return procedure.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Your withdrawal has been registered under reference %s. An acknowledgment of receipt has been sent to you by email. As your order has not yet been shipped, no product return will be necessary: after verification, the shipment will be cancelled and you will be refunded.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Our customer service will verify the eligibility of your request (14-day legal period, exclusions under article L221-28). If it is compliant, the return procedure will be sent to you by email, then the refund will be made no later than 14 days after recovery of the goods or receipt of proof of shipment. Please do not return the product before receiving the return procedure.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'As your order has not yet been shipped, no product return will be necessary. After verification of your request by our customer service, the shipment will be cancelled and the full amount paid will be refunded to you no later than 14 days after your request, using the same means of payment (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'To check: 14-day period, legal exclusions (art. L221-28), products already returned.';
$_MODULE['<{retractationcommande}prestashop>demande_ecbc815f858a7d4a0ff0fe67f6eea2a3'] = 'ORDER NOT SHIPPED — cancellation before shipment: no product return expected. To check: legal exclusions (art. L221-28). Remember to block the shipment before validating.';
$_MODULE['<{retractationcommande}prestashop>demande_5f0d073c461f238ea2622dc70766a38f'] = 'Not shipped at the time of the request';
